($$Dads' Club at Best Start Family Hub: Leytonstone$$, $$2-8 Cathall Road, Leytonstone, London E11 4LF$$, $$E11 4LF$$, null, null, $$Family activities$$, $$10:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=2-8%20Cathall%20Road%2C%20Leytonstone%2C%20London%20E11%204LF$$, $$https://www.walthamforest.gov.uk/events$$, null, null, 0, $$Under-4s$$, $$Waltham Forest$$, '{}', null, $$18 April, 16 May, 20 June, 18 July$$, $$Dads' Club from Waltham Forest Best Start in Life timetable. Check the council events page before travelling.$$, $$Check source$$, false, $$Waltham Forest Best Start in Life timetable$$, $$https://www.walthamforest.gov.uk/media/11253#dads-club-best-start-family-hub-leytonstone-10-00-18-april-16-may-20-june-18-july$$, null, $$https://www.walthamforest.gov.uk/media/11253$$, null, '{}', $$2026-04-01$$, $$2026-08-31$$, '{}', $$specific_dates$$, $$From April-August 2026 Best Start timetable. Frequency: 18 April, 16 May, 20 June, 18 July. Verify live details at walthamforest.gov.uk/events.$$, $$published$$),
($$Kids' Crafts Club at Leytonstone Library$$, $$Church Lane, Leytonstone, London E11 1HG$$, $$E11 1HG$$, null, null, $$Stay & play$$, $$11:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=Church%20Lane%2C%20Leytonstone%2C%20London%20E11%201HG$$, $$https://www.walthamforest.gov.uk/events$$, null, null, 0, $$2 years and above$$, $$Waltham Forest$$, '{}', $$FREQ=WEEKLY$$, $$Weekly$$, $$Kids' Crafts Club from Waltham Forest Best Start in Life timetable. Check the council events page before travelling.$$, $$Check source$$, false, $$Waltham Forest Best Start in Life timetable$$, $$https://www.walthamforest.gov.uk/media/11253#kids-crafts-club-leytonstone-library-11-00-weekly$$, null, $$https://www.walthamforest.gov.uk/media/11253$$, null, '{}', $$2026-04-01$$, $$2026-08-31$$, '{}', $$date_range$$, $$From April-August 2026 Best Start timetable. Frequency: Weekly. Verify live details at walthamforest.gov.uk/events.$$, $$published$$),
($$Stay and Play at Leytonstone Library$$, $$Church Lane, Leytonstone, London E11 1HG$$, $$E11 1HG$$, null, null, $$Stay & play$$, $$14:00$$, $$15:00$$, $$https://www.google.com/maps/search/?api=1&query=Church%20Lane%2C%20Leytonstone%2C%20London%20E11%201HG$$, $$https://www.walthamforest.gov.uk/events$$, null, null, 0, $$Under-5s and families$$, $$Waltham Forest$$, '{}', $$FREQ=WEEKLY$$, $$Weekly$$, $$Stay and Play from Waltham Forest Best Start in Life timetable. Check the council events page before travelling.$$, $$Check source$$, false, $$Waltham Forest Best Start in Life timetable$$, $$https://www.walthamforest.gov.uk/media/11253#stay-and-play-leytonstone-library-14-00-weekly$$, null, $$https://www.walthamforest.gov.uk/media/11253$$, null, '{}', $$2026-04-01$$, $$2026-08-31$$, '{}', $$date_range$$, $$From April-August 2026 Best Start timetable. Frequency: Weekly. Verify live details at walthamforest.gov.uk/events.$$, $$published$$),
($$Infant Feeding Group Session at Best Start Family Hub: Leytonstone$$, $$2-8 Cathall Road, Leytonstone, London E11 4LF$$, $$E11 4LF$$, null, null, $$Feeding & postnatal support$$, $$13:00$$, $$14:30$$, $$https://www.google.com/maps/search/?api=1&query=2-8%20Cathall%20Road%2C%20Leytonstone%2C%20London%20E11%204LF$$, $$https://www.walthamforest.gov.uk/events$$, null, null, 0, $$Parents, babies and under-5s$$, $$Waltham Forest$$, '{}', $$FREQ=WEEKLY$$, $$Weekly$$, $$Infant Feeding Group Session from Waltham Forest Best Start in Life timetable. Check the council events page before travelling.$$, $$Check source$$, false, $$Waltham Forest Best Start in Life timetable$$, $$https://www.walthamforest.gov.uk/media/11253#infant-feeding-group-session-best-start-family-hub-leytonstone-13-00-weekly$$, null, $$https://www.walthamforest.gov.uk/media/11253$$, null, '{}', $$2026-04-01$$, $$2026-08-31$$, '{}', $$date_range$$, $$From April-August 2026 Best Start timetable. Frequency: Weekly. Verify live details at walthamforest.gov.uk/events.$$, $$published$$),
($$Church Lane Community Garden$$, $$Church Lane Community Garden, London E11 4QX, UK$$, $$E11 4QX$$, null, null, $$Parks & outdoor play$$, $$10:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=Church%20Lane%20Community%20Garden%2C%20London%20E11%204QX%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/church-lane-community-garden$$, null, null, 0, $$Families and children$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$The garden grows vegetables, herbs and fruit using organic methods, in a mixture of raised beds and larger beds of perennial vegetables. Volunteers are on hand whenever the garden is open, to chat and offer gardening advice or suggestions. Seeds, plants and pots are available, and there's a selection of garden tools available to borrow as well as gardening books for reference. We have a community-built pizza oven which we would normally use for events over the summer (but currently needs repairing), and an apple press for juicing local apples that might otherwise go to waste. There are occasional work days, workshops and skill share sessions on various topics. Do get in touch if there's an event you'd like to help organise, a skill you'd like to share, or if you have an idea for a workshop. Phone: &#8203; Email: cg@transitionleytonstone.org.uk$$, $$Check source$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/church-lane-community-garden$$, $$https://static.wixstatic.com/media/c24df7_2241a40e51294263a29f435bece73596~mv2.jpg/v1/fill/w_2448,h_3264,al_c,q_90/IMG_0987.JPG$$, $$https://www.transitionleytonstone.org.uk/green-directory/church-lane-community-garden$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Geek Cafe$$, $$728 High Rd Leytonstone, Bushwood, London E11 3AJ, UK$$, $$E11 3AJ$$, null, null, $$Child-friendly cafes$$, $$09:00$$, $$17:00$$, $$https://www.google.com/maps/search/?api=1&query=728%20High%20Rd%20Leytonstone%2C%20Bushwood%2C%20London%20E11%203AJ%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/geek-cafe$$, null, null, 0, $$Parents, babies and families$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$Geek Cafe is a Community Interest Company providing technical support and services to the local community. It is a learning hub, helping people to get the most out of their computer, and build their IT skills. Everyone is welcome, especially seniors. We repair, refurbish and resell computers, and we are also able to provide some refurbished computers to people/organisations in the community. In addition, we recycle computer parts, encouraging people to donate equipment they no longer use. Even out of date parts can be recycled or used by local young people to create exciting, imaginative works of art! Geek Cafe is also a place to uplift people! We run regular social sessions for men and women in the community. It is a safe space to share a cuppa, exchange a story, and talk about things together. We are also very aware that loneliness is an increasing problem in our society, so we want people to know that our door is open for a drop-in and chat. Phone: 07404 470404 Email: geekcafecic@gmail.com$$, $$Cafe purchases$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/geek-cafe$$, $$https://static.wixstatic.com/media/f2e5fe_c52b6b31bcd645c396ef9305d88eac43~mv2.jpg/v1/fill/w_2048,h_1536,al_c,q_90/Geek%20cafe.jpg$$, $$https://www.transitionleytonstone.org.uk/green-directory/geek-cafe$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Kinship in Nature$$, $$Friends Meeting House, Burial Ground, Bush Rd, London E11 3AU, UK$$, $$E11 3AU$$, null, null, $$Parks & outdoor play$$, $$10:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=Friends%20Meeting%20House%2C%20Burial%20Ground%2C%20Bush%20Rd%2C%20London%20E11%203AU%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/kinship-in-nature$$, null, null, 0, $$Families and children$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$Kinship in Nature is a female founded project striving to connect people with nature, not only to nurture people's wellbeing but to protect the planet and create a sustainable future for generations to come. We believe being nature connected is not only essential as a foundation for healthy childhood but for everyone's wellbeing, especially when living in a city like London. We offer opportunities for children (weekly family sessions, ongoing groups & forest camps) and adults including workshops, first aid training, forest school leadership level 3 training and fully funded traineeships. Phone: 07968 771716 (prefers WhatsApp) Email: hello@kinshipinnature.com$$, $$Check source$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/kinship-in-nature$$, $$https://static.wixstatic.com/media/f2e5fe_d5bd06562c0347e89f720e216e34e3e6~mv2.png/v1/fill/w_1920,h_1279,al_c/Kinship%20in%20Nature.png$$, $$https://www.transitionleytonstone.org.uk/green-directory/kinship-in-nature$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Perky Blenders$$, $$660 High Road Leyton, London E10 6JP, UK$$, $$E10 6JP$$, null, null, $$Child-friendly cafes$$, $$09:00$$, $$17:00$$, $$https://www.google.com/maps/search/?api=1&query=660%20High%20Road%20Leyton%2C%20London%20E10%206JP%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/perky-blenders$$, null, null, 0, $$Parents, babies and families$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$At Perky Blenders, responsibility is one of our core values-it shapes the way we source, serve, and deliver our coffee. We believe great coffee should have a positive impact, and we're always looking for ways to reduce waste and tread more lightly on the planet. We partner with Wheelie Goods to deliver our coffee by bike to our wholesale customers within a 10km radius of our East London Roastery. In 2024 alone, we delivered 22 tonnes of coffee and covered over 4,000 miles on two wheels, proving that sustainability and convenience can go hand in hand. Being responsible also means tackling waste head-on. We collect used coffee bags in-store for recycling and are passionate about reducing single-use cups, with that in mind, we've committed to never knowingly sharing content that promotes them. Our commitment goes beyond the cup. Used coffee grounds from our shops doesn't go to waste; they're either delivered by bike to local allotment projects to enrich the soil or sent to our friends at Soapsmith, where they're transformed into their signature Coffee Scrub. Sourcing responsibly is just as important. We build long-term relationships with producers like San Coffee, ensuring ethical, environmentally sound practices from farm to cup. Responsibility isn't just a value-it's a promise. Every step we take is a step towards a greener future. Phone: 0203 868 6386 Email: hello@perkyblenders.com$$, $$Cafe purchases$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/perky-blenders$$, $$https://static.wixstatic.com/media/f2e5fe_39f59187bd1f4cc297cff329d2ec2d9e~mv2.jpg/v1/fill/w_481,h_629,al_c,q_80/Perky%20B%20Roastery.jpg$$, $$https://www.transitionleytonstone.org.uk/green-directory/perky-blenders$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Stone Mini Market$$, $$721 High Road Leytonstone, London E11 4RD, UK$$, $$E11 4RD$$, null, null, $$Child-friendly cafes$$, $$09:00$$, $$17:00$$, $$https://www.google.com/maps/search/?api=1&query=721%20High%20Road%20Leytonstone%2C%20London%20E11%204RD%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/stone-mini-market$$, null, null, 0, $$Parents, babies and families$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$Hidden behind the beer, this local grocery shop features a refill station for cleaning products, dried foods, herbs, and spices. It proudly stocks a variety of ethically sourced, organic foods and is committed to further reducing plastic packaging across all goods sold. The Mini Market offers an astonishing selection of craft beers, supporting independent small breweries, including those in East London. With a personal goal to be 'more kind to the Earth and other species,' the shop's growing range of vegan products also caters to those on restricted diets for health or religious reasons. All packaging is recycled or reused whenever possible, shop appliances are sourced second-hand, and the employees are all local. In addition to serving as a grocery store, there is a function room at the back that hosts regular activities such as knitting and sewing groups, games nights, repair cafes, author readings, BSL lessons, and private functions. Transition Leytonstone's Library for Change is also hosted here. This transforms the shop into a welcoming space for the community to engage and participate, rather than just a place for transactions. Additionally, it houses the Convivium Gallery, featuring a permanent exhibition by local artists, showcasing the vibrant creativity within the community. Phone: &#8203; Email: leytonstonemm@gmail.com$$, $$Cafe purchases$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/stone-mini-market$$, $$https://static.wixstatic.com/media/f2e5fe_d7a92d01862f4cd9b73574e4db7f0402~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_90/Mini%20Market.jpg$$, $$https://www.transitionleytonstone.org.uk/green-directory/stone-mini-market$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Tamping Grounds$$, $$324 Cann Hall Road, London E11 3NW, UK$$, $$E11 3NW$$, null, null, $$Child-friendly cafes$$, $$09:00$$, $$17:00$$, $$https://www.google.com/maps/search/?api=1&query=324%20Cann%20Hall%20Road%2C%20London%20E11%203NW%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/tamping-grounds$$, null, null, 0, $$Parents, babies and families$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$Usman and Zak run this welcoming and popular coffee shop serving a variety of pastries and cakes, as well as toasties. They also sell freshly baked bread sourced from Leytonstone or Hackney. Tamping Grounds also has a branch at 179 Francis Road, E10 6NQ, and has now opened at Stone Mini Market, 721 High Road Leytonstone, London E11 4RD. Sustainability is at the heart of their business. The coffee is from Fireheart, a certified B Corp. This accreditation indicates that they reach a high standard of social and environmental performance. For example, in this case, they make sure that the farmers who grow the coffee receive a decent living wage. https://bcorporation.uk/ All packaging used is recyclable, and much of it, including takeaway cups and lids, is compostable. They sell tote bags for customers to use and re-use. Where possible, items are re-used rather than recycled. Cardboard packaging is passed on to a local company that re-uses it. In the case of plastic milk tops, one of the few plastic items passing through Tamping Grounds, these are given to a local man who recycles them to make incense holders, which are also sold in the shop. All staff live locally, and most use public transport, or walk or cycle to work. A car is only used for unavoidable journeys between the two shops. The shops are child and dog friendly. Phone: 07776 662212 Email: tampinggrounds@hotmail.com$$, $$Cafe purchases$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/tamping-grounds$$, $$https://static.wixstatic.com/media/f2e5fe_84663227beed4f85899f775a7962ef9b~mv2.jpg/v1/fill/w_680,h_510,al_c,q_80/Tamping%20Grounds.jpg$$, $$https://www.transitionleytonstone.org.uk/green-directory/tamping-grounds$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$The Library for Change$$, $$647-661 High Rd Leytonstone, Bushwood, London E11 4RD, UK$$, $$E11 4RD$$, null, null, $$Family activities$$, $$10:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=647-661%20High%20Rd%20Leytonstone%2C%20Bushwood%2C%20London%20E11%204RD%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/the-library-for-change$$, null, null, 0, $$Families and children$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$The library is a collection of over 300 books on a wide range of topics relating to the changes that need to happen in response to the climate and ecological crisis we face. There are practical books on gardening and mending, academic books on economics, books of eco poetry, nature books for children. There are classics from the 1970's (Small is Beautiful, by E.F. Schumacher), and books published in the last couple of years (The Climate Change Garden, by Sally Morgan and Kim Stoddart). The library is hosted by Mattcup, the coffee shop in the Continental Food Exchange near Leytonstone High Road station. It is free to join, which can be done in the library by scanning the QR code on the poster, or through the Transition Leytonstone website (see below). Once you've joined, you can use the library whenever the cafe is open. The Library for Change also runs events, including talks and writing workshops. Details of these will be in Transition Leytonstone's monthly newsletter. You can sign up for this on the website. Phone: &#8203; Email: library@transitionleytonstone.org.uk$$, $$Check source$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/the-library-for-change$$, $$https://static.wixstatic.com/media/f2e5fe_cfb423440c1d4645946ffa201410eecd~mv2.jpg/v1/fill/w_2250,h_1635,al_c,q_90/library%20in%20cafe_edited.jpg$$, $$https://www.transitionleytonstone.org.uk/green-directory/the-library-for-change$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$),
($$Wren Wildlife and Conservation Group$$, $$65 Belgrave Road, London E11 3QP, UK$$, $$E11 3QP$$, null, null, $$Parks & outdoor play$$, $$10:00$$, $$12:00$$, $$https://www.google.com/maps/search/?api=1&query=65%20Belgrave%20Road%2C%20London%20E11%203QP%2C%20UK$$, $$https://www.transitionleytonstone.org.uk/green-directory/wren-wildlife-and-conservation-group$$, null, null, 0, $$Families and children$$, $$Waltham Forest$$, '{}', null, $$Check opening times or session details with the venue before travelling.$$, $$The WREN Wildlife and Conservation Group engages with the wildlife of the local area in a variety of ways. Members record local species and regularly submit data to key national databases for scientific research. Current projects cover butterflies, moths, grass-snakes and wildflowers, as well as bird watching and recording, which is carried out on an ongoing basis. They can help identify rare and unusual species. A group of volunteers carries out practical work to clear and conserve habitat and enhance biodiversity. This is done mainly in Wanstead Park, but also in other areas such as Wanstead Flats. New volunteers are welcome for practical work and recording.Wren works to introduce wildlife to local people through walks and talks. Examples of species covered include bats, waterbirds, migrant species, fungi and wildflowers. An annual weekend festival takes place in Wanstead Park, celebrating the diversity of local wildlife. Last year's event featured educational work with children and young people. Wren's quarterly newsletter can be downloaded from the website. Phone: &#8203; Email: wrenconservationgroup@gmail.com wrenmembers@gmail.com$$, $$Check source$$, false, $$Transition Leytonstone Green Directory$$, $$https://www.transitionleytonstone.org.uk/green-directory/wren-wildlife-and-conservation-group$$, $$https://static.wixstatic.com/media/f2e5fe_2245919f4b444729998b7c1fbd768cc4~mv2.png/v1/fill/w_1024,h_683,al_c/WREN%20Wildlife%20and%20Conservation%20Group.png$$, $$https://www.transitionleytonstone.org.uk/green-directory/wren-wildlife-and-conservation-group$$, null, '{}', null, null, '{}', $$daily$$, $$Local directory listing; check venue for opening times.$$, $$published$$)
